{
  "schemaVersion": 3,
  "arcId": "arc_1_khoi_nghiep_beo_tay",
  "startChapter": 1,
  "endChapter": 30,
  "direction": "Lâm sử dụng kiến thức bảo quản bằng bèo tây để kiếm vốn từ cá dạt, từng bước nâng cấp công cụ từ thúng tre lên xe kéo, lập trạm thu mua và bắt đầu thay đổi thói quen đánh bắt của ngư dân.",
  "terminalChange": "Lâm chuyển từ tay trắng sang sở hữu một trạm thu mua lợp lá, có xe kéo tay, mua được đá viên từ nhà máy và bước đầu thuyết phục được Lão Bốn cùng ngư dân hạn chế lưới tận diệt.",
  "activeConflicts": [
    {
      "id": "conflict_bon_ben_bai",
      "actorIds": [
        "char_lam",
        "char_bon"
      ],
      "objective": "Lâm muốn thu mua cá dạt thuận lợi và lập lán tại bến; Lão Bốn muốn duy trì quyền lực và thu phí bến bãi tối đa.",
      "leverage": "Lão Bốn nắm quyền quản lý bến cá và đội tàu; Lâm có khả năng bao tiêu toàn bộ cá dạt giúp bến sạch sẽ và thanh toán sòng phẳng.",
      "nextMove": "Lão Bốn tăng tiền bến bãi khi thấy Lâm có lãi, Lâm đàm phán bằng cách nhận trách nhiệm dọn dẹp bến và trả tiền cọc trước."
    },
    {
      "id": "conflict_thim_hai_ep_gia",
      "actorIds": [
        "char_lam",
        "char_thim_hai"
      ],
      "objective": "Lâm muốn bán cá với giá cao tương xứng độ tươi; Thím Hai muốn ép giá để tối ưu lợi nhuận quán cơm.",
      "leverage": "Thím Hai là khách hàng mua sỉ lớn nhất chợ huyện; Lâm là người duy nhất cung cấp được cá dạt tươi rói không cần đá lạnh.",
      "nextMove": "Thím Hai chê cá nhỏ để giảm giá, Lâm kiên quyết giữ giá bằng cách phân loại rõ ràng và dọa bán cho quán đối thủ."
    }
  ],
  "duePromiseIds": [
    "prom_1",
    "prom_3",
    "prom_4"
  ],
  "progressionBudget": [
    {
      "signal": "Từ việc ăn cháo trắng sang những bữa cơm có thịt lợn và cá ngon",
      "requiredChange": "Bán thành công mẻ cá dạt đầu tiên ở chợ huyện, dùng tiền lãi mua ngay gạo thơm và thịt lợn về nấu cho Mai."
    },
    {
      "signal": "Từ gánh thúng tre sang sở hữu xe kéo tay bằng gỗ",
      "requiredChange": "Tích lũy đủ 5000 đồng sau nhiều chuyến gánh bộ, đặt thợ mộc đóng xe kéo để tăng sản lượng vận chuyển."
    },
    {
      "signal": "Từ việc mua cá dạt lẻ tẻ sang lập trạm thu mua lợp lá",
      "requiredChange": "Gom đủ 50000 đồng, thuyết phục Lão Bốn cho thuê một góc bến cá để dựng lán lợp lá, chính thức lập trạm thu mua."
    }
  ]
}
